/// Compile-time checks that the aggregate result types are nullable (except `COUNT`) and that
/// integer `SUM` widens to `i64`.
#[test]
fn test_aggregate_result_types() {
    let count: <CountExpr<i32> as ExprKind>::Value = 0i64;
    let _: i64 = count;

    // ≤32-bit operands sum to `i64`; 64-bit and wider widen to `i128` to match PostgreSQL's
    // `numeric` result and avoid a narrowing `bigint` cast.
    let sum: <SumExpr<i32> as ExprKind>::Value = Some(0i64);
    let _: Option<i64> = sum;

    let wide_sum: <SumExpr<i64> as ExprKind>::Value = Some(0i128);
    let _: Option<i128> = wide_sum;

    // `u128` keeps an unsigned sum: a single value can exceed `i128::MAX`.
    let unsigned_sum: <SumExpr<u128> as ExprKind>::Value = Some(0u128);
    let _: Option<u128> = unsigned_sum;

    let avg: <AvgExpr<i32> as ExprKind>::Value = Some(0.0f64);
    let _: Option<f64> = avg;

    let min: <MinExpr<i32> as ExprKind>::Value = Some(0i32);
    let _: Option<i32> = min;

    let max: <MaxExpr<String> as ExprKind>::Value = Some(String::new());
    let _: Option<String> = max;
}

/// Exhaustive compile-time check of the `SUM` widening for every numeric operand type. ≤32-bit
/// integers sum to `i64`; 64-bit-and-wider signed/`bigint`-stored operands to `i128`; `u128` stays
/// unsigned (a single value can exceed `i128::MAX`); floats to `f64`. Each is also asserted to be
/// decodable on PostgreSQL by [`sum_result_types_decode_on_postgres`] there.
#[test]
fn test_sum_widening_for_every_numeric_operand() {
    fn sum_is<K, Expected>()
    where
        K: ExprKind,
        SumExpr<K>: ExprKind<Value = Option<Expected>>,
    {
    }

    sum_is::<i8, i64>();
    sum_is::<i16, i64>();
    sum_is::<i32, i64>();
    sum_is::<u8, i64>();
    sum_is::<u16, i64>();

    sum_is::<i64, i128>();
    sum_is::<isize, i128>();
    sum_is::<u32, i128>();
    sum_is::<u64, i128>();
    sum_is::<usize, i128>();
    sum_is::<i128, i128>();

    sum_is::<u128, u128>();

    sum_is::<f32, f64>();
    sum_is::<f64, f64>();
}

/// Compile-time checks that aggregates over a nullable operand kind (`Nullable<K>`, as produced by
/// a `left_join`) unwrap the nullability: `SUM` still widens to `Option<i64>`, and `MIN` stays a
/// single `Option<i32>` rather than nesting a second `Option`.
#[test]
fn test_aggregate_nullable_operand_types_unwrap() {
    let sum: <SumExpr<Nullable<i32>> as ExprKind>::Value = Some(0i64);
    let _: Option<i64> = sum;

    let avg: <AvgExpr<Nullable<i32>> as ExprKind>::Value = Some(0.0f64);
    let _: Option<f64> = avg;

    let min: <MinExpr<Nullable<i32>> as ExprKind>::Value = Some(0i32);
    let _: Option<i32> = min;
}

#[test]
fn test_group_by_allows_mixed_projection() {
    // A grouped query may select a grouping key alongside an aggregate (rejected without GROUP BY).
    let q = TestConnection
        .from::<User>()
        .group_by(|(user,)| user.name)
        .select(|(user,)| (user.name, user.id.count()));
    assert_eq!(
        q.to_sql(),
        "SELECT q0_0.name AS t0_name, COUNT(q0_0.id) AS t1_expr \
         FROM public.users AS q0_0 GROUP BY q0_0.name"
    );
}

#[test]
fn test_group_by_having_full_clause_order() {
    // WHERE -> GROUP BY (multiple keys) -> HAVING (aggregate) -> ORDER BY, with params in order.
    let q = TestConnection
        .from::<User>()
        .where_(|user| user.id.greater_than(0))
        .group_by(|(user,)| user.id)
        .group_by(|(user,)| user.name)
        .having(|(user,)| user.id.count().greater_than(1i64))
        .order_by(|(user,)| user.name.asc())
        .select(|(user,)| (user.id, user.name, user.id.count()));
    assert_eq!(
        q.to_sql(),
        "SELECT q0_0.id AS t0_id, q0_0.name AS t1_name, COUNT(q0_0.id) AS t2_expr \
         FROM public.users AS q0_0 WHERE (q0_0.id > ?) GROUP BY q0_0.id, q0_0.name \
         HAVING (COUNT(q0_0.id) > ?) ORDER BY q0_0.name ASC"
    );
    assert_eq!(
        q.collect_params().unwrap(),
        vec![TestParam::Int(0), TestParam::Int(1)]
    );
}

#[test]
fn test_having_without_group_by_on_whole_table_aggregate() {
    // `HAVING` is valid without `GROUP BY` over a whole-table aggregate, and may use aggregates.
    let q = TestConnection
        .from::<User>()
        .having(|(user,)| user.id.count().greater_than(0i64))
        .select(|(user,)| user.id.count());
    assert_eq!(
        q.to_sql(),
        "SELECT COUNT(q0_0.id) AS expr FROM public.users AS q0_0 HAVING (COUNT(q0_0.id) > ?)"
    );
}

#[test]
fn test_group_by_tuple_matches_chained_keys() {
    // A tuple of keys in one call renders identically to chaining `group_by`.
    let tuple = TestConnection
        .from::<User>()
        .group_by(|(user,)| (user.id, user.name))
        .select(|(user,)| (user.id, user.name, user.id.count()));
    let chained = TestConnection
        .from::<User>()
        .group_by(|(user,)| user.id)
        .group_by(|(user,)| user.name)
        .select(|(user,)| (user.id, user.name, user.id.count()));
    assert_eq!(
        tuple.to_sql(),
        "SELECT q0_0.id AS t0_id, q0_0.name AS t1_name, COUNT(q0_0.id) AS t2_expr \
         FROM public.users AS q0_0 GROUP BY q0_0.id, q0_0.name"
    );
    assert_eq!(tuple.to_sql(), chained.to_sql());
}

#[test]
fn test_having_tuple_predicates_are_anded() {
    // A tuple of HAVING predicates is AND-joined, identically to chaining `having`.
    let q = TestConnection
        .from::<User>()
        .group_by(|(user,)| user.name)
        .having(|(user,)| {
            (
                user.id.count().greater_than(1i64),
                user.id.count().less_than(10i64),
            )
        })
        .select(|(user,)| (user.name, user.id.count()));
    assert_eq!(
        q.to_sql(),
        "SELECT q0_0.name AS t0_name, COUNT(q0_0.id) AS t1_expr \
         FROM public.users AS q0_0 GROUP BY q0_0.name \
         HAVING (COUNT(q0_0.id) > ?) AND (COUNT(q0_0.id) < ?)"
    );
    assert_eq!(
        q.collect_params().unwrap(),
        vec![TestParam::Int(1), TestParam::Int(10)]
    );
}
